import React, { useState } from 'react';

const Marketplace = () => {
  // १. स्टेट: कौन सी कैटेगरी चुनी गई है?
  const [selectedCategory, setSelectedCategory] = useState(null);

  // २. डेटा: हर कैटेगरी के अंदर क्या दिखेगा (इसे आप बाद में बदल सकते हैं)
  const data = {
    "Academic Projects": [
      { id: 1, title: "Library Management", price: "₹1500" },
      { id: 2, title: "E-commerce Website", price: "₹2500" }
    ],
    "Assignments": [
      { id: 1, title: "Java OOPs Concept", price: "₹300" },
      { id: 2, title: "Python Data Science", price: "₹500" }
    ],
    "Notes & Resources": [
      { id: 1, title: "React Interview Questions", price: "Free" },
      { id: 2, title: "Node.js PDF Notes", price: "₹100" }
    ]
  };

  return (
    <div style={styles.container}>
      <h1 style={styles.heading}>Select a Category</h1>

      {/* ३. कैटेगरी कार्ड्स (आपकी इमेज जैसा डिजाइन) */}
      <div style={styles.categoryGrid}>
        {Object.keys(data).map((cat) => (
          <div 
            key={cat} 
            style={selectedCategory === cat ? styles.activeCard : styles.card}
            onClick={() => setSelectedCategory(cat)}
          >
            {cat}
          </div>
        ))}
      </div>

      <hr style={styles.divider} />

      {/* ४. चुना हुआ कंटेंट यहाँ दिखेगा */}
      <div style={styles.contentArea}>
        {selectedCategory ? (
          <div>
            <h2 style={{color: '#00d2ff'}}>{selectedCategory} Items:</h2>
            <div style={styles.itemGrid}>
              {data[selectedCategory].map(item => (
                <div key={item.id} style={styles.itemCard}>
                  <h3>{item.title}</h3>
                  <p>Price: {item.price}</p>
                  <button style={styles.btn}>Buy Now</button>
                </div>
              ))}
            </div>
          </div>
        ) : (
          <p style={{textAlign: 'center', color: '#888'}}>कृपया ऊपर दी गई किसी कैटेगरी पर क्लिक करें।</p>
        )}
      </div>
    </div>
  );
};

// डिजाइन स्टाइल्स (इमेज के हिसाब से डार्क थीम)
const styles = {
  container: { background: '#000', minHeight: '100vh', padding: '50px', color: '#fff' },
  heading: { textAlign: 'center', fontSize: '32px', marginBottom: '40px' },
  categoryGrid: { display: 'flex', justifyContent: 'center', gap: '20px', flexWrap: 'wrap' },
  card: { 
    background: '#111', border: '1px solid #333', padding: '30px 20px', 
    borderRadius: '15px', cursor: 'pointer', minWidth: '200px', textAlign: 'center' 
  },
  activeCard: { 
    background: '#222', border: '1px solid #00d2ff', padding: '30px 20px', 
    borderRadius: '15px', cursor: 'pointer', minWidth: '200px', textAlign: 'center', color: '#00d2ff' 
  },
  divider: { margin: '40px 0', border: '0.1px solid #222' },
  contentArea: { maxWidth: '1000px', margin: '0 auto' },
  itemGrid: { display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(250px, 1fr))', gap: '20px', marginTop: '20px' },
  itemCard: { background: '#1a1a1a', padding: '20px', borderRadius: '10px', border: '1px solid #333' },
  btn: { background: '#00d2ff', border: 'none', padding: '10px', borderRadius: '5px', width: '100%', marginTop: '10px', cursor: 'pointer', fontWeight: 'bold' }
};

export default Marketplace;
